// Get inputs from previous nodes
const openPeriods = $('Call \'Nudge Excel Config\'').item.json.openPeriods;
const sentDay = new Date($('Start').item.json.sentDateTime);

const rawDelay = Number($json.recommendedDelayInHours ?? $json.output.recommendedDelayInHours);
const shouldFollowUp = ($json.shouldFollowUp ?? $json.output.shouldFollowUp);

// Early exit if no follow-up needed
if (!shouldFollowUp) {
  return {
    nextFollowUpAt: "",
    finalDelayUsed: 0,
    usedFallback: false
  };
}

// Calculate delay
let delay;
if (isNaN(rawDelay) || rawDelay <= 0) {
  delay = getFallbackDelay($json.output);
} else {
  delay = Math.max(1, rawDelay);
}

// Compute initial follow-up time
let followUp = new Date(sentDay);
followUp.setTime(sentDay.getTime() + delay * 60 * 60 * 1000);

// --- NEW LOGIC: constrain to valid open periods (UTC-based) ---
const validSet = generateValidIntervalSet(openPeriods);
const followUpHour = followUp.getUTCHours();
const adjustedHour = getValidTime(validSet, followUpHour);

// Preserve minutes/seconds/milliseconds
const minutes = followUp.getUTCMinutes();
const seconds = followUp.getUTCSeconds();
const ms = followUp.getUTCMilliseconds();

if (adjustedHour !== followUpHour) {
  if (adjustedHour >= 24) {
    // rollover to next dayâ€™s min
    followUp.setUTCDate(followUp.getUTCDate() + 1);
    followUp.setUTCHours(adjustedHour - 24, minutes, seconds, ms);
  } else {
    followUp.setUTCHours(adjustedHour, minutes, seconds, ms);
  }
}

// Final output
return {
  nextFollowUpAt: followUp.toISOString(),
  finalDelayUsed: delay,
  usedFallback: delay !== rawDelay
};

// --- Helper functions ---
function getFallbackDelay(output) {
  if (output.urgency === "high") return 1;
  if (output.urgency === "medium") return 2;
  if (output.urgency === "low") return 4;
  return 3;
}

function generateValidIntervalSet(myvalidinterval) {
  const validintervalset = new Set();

  if (!Array.isArray(myvalidinterval)) return validintervalset;

  for (const interval of myvalidinterval) {
    if (!Array.isArray(interval) || interval.length !== 2) continue;

    const int0 = Number(interval[0]);
    const int1 = Number(interval[1]);

    if (Number.isNaN(int0) || Number.isNaN(int1)) continue;
    if (int0 < 0 || int0 > 23 || int1 < 0 || int1 > 23) continue;

    const mini = Math.min(int0, int1);
    const maxi = Math.max(int0, int1);

    for (let i = mini; i <= maxi; i++) {
      validintervalset.add(i);
    }
  }

  return validintervalset;
}

function getValidTime(myvalidintervalset, time) {
  try {
    myvalidintervalset = new Set(myvalidintervalset);

    if (myvalidintervalset.size === 0) return time;

    const arr = Array.from(myvalidintervalset).sort((a, b) => a - b);

    const min = arr[0];
    const max = arr[arr.length - 1];

    if (time <= min) return min;
    if (time > max) return min + 24; // next dayâ€™s min

    if (myvalidintervalset.has(time)) return time;

    for (let val of arr) {
      if (val >= time) return val;
    }

    return time;
  } catch (e) {
    return time;
  }
}

// Get inputs
let text = ($('Is Prompt error').item.json.followupMessage ?? 
           $('Is Prompt error').item.json.output?.followupMessage) || '';

text += "/n/n" + $('Call \'Nudge Excel Config\'').item.json.aiWarningText;

let tokens = $('Call \'Redactor\' body').item.json.tokenMap;

// Ensure tokens is an object
if (typeof tokens === 'string') {
  try {
    tokens = JSON.parse(tokens);
  } catch (err) {
    tokens = {};
  }
}
if (!tokens || typeof tokens !== 'object') {
  tokens = {};
}

// Escape regex special characters
function escapeRegex(str) {
  if (typeof str !== 'string') return '';
  return str.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

// Replace tokens safely
for (const key in tokens) {
  // Skip invalid keys
  if (typeof key !== 'string' || !key.trim()) continue;

  const value = tokens[key];

  // Skip invalid values
  if (typeof value !== 'string') continue;

  let replacement = value;

  // URL handling (optional â€” here just passes through)
  if (value.startsWith('http://') || value.startsWith('https://')) {
    replacement = `<a href="${value}">${value}</a>`;
  }

  const regex = new RegExp(escapeRegex(key), 'g');
  text = text.replace(regex, replacement);
}

// Return result
return {
  storedMessage: text
};

let html = $('Start').item.json.body_content;

// Remove scripts/styles
html = html.replace(/<style[\s\S]*?<\/style>/gi, '');
html = html.replace(/<script[\s\S]*?<\/script>/gi, '');

// Replace <br> and block tags with newlines
html = html.replace(/<br\s*\/?>/gi, '\n');
html = html.replace(/<\/div>/gi, '\n');
html = html.replace(/<\/p>/gi, '\n');

// Remove all remaining HTML tags
let text = html.replace(/<[^>]+>/g, '');

// Decode basic HTML entities
text = text
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>');

// Clean extra whitespace
text = text.replace(/\n\s*\n/g, '\n\n').trim();

return {
  body: text
};

return {
  messageId: $('Start').item.json.id,
  conversationId: $('Start').item.json.conversationId,
  subject: $('Start').item.json.subject,
  recipient: $('Start').item.json.toRecipients[0].emailAddress.address,
  sender: $('Start').item.json.sender_emailAddress_address,
  sentTime: $('Start').item.json.sentDateTime,
  originalSentTime: $('Start').item.json.sentDateTime,
  status: "unprompted",
};

const errJson = $('Is Prompt error').item.json;
const errOut = errJson?.output ?? {};

const shouldFollowUp = errJson.shouldFollowUp ?? errOut.shouldFollowUp;
const status = shouldFollowUp ? "pending" : "skipped";

return {
  messageId: $('Start').item.json.id,
  status,
  shouldFollowUp,
  followUpMessage: $('if old status is unprompted1').item.json.storedMessage,
  nextFollowUpAt: $('Get Followup time').item.json.nextFollowUpAt ?? $('Get Followup time').item.json.output.nextFollowUpAt,
  urgency: errJson.urgency ?? errOut.urgency,
  relationship: errJson.relationship ?? errOut.relationship,
  nature: errJson.nature ?? errOut.nature,
  timeSensitivity: errJson.timeSensitivity ?? errOut.timeSensitivity,
  recommendedDelayInHours: errJson.recommendedDelayInHours ?? errOut.recommendedDelayInHours,
  reason: errJson.reason ?? errOut.reason,
  followUpCount: 0,
};
